<template><el-card><template #header>测试用例库</template><PageToolbar><el-input v-model="q" placeholder="搜索用例"/><template #actions><el-button type="primary" @click="add">新建用例</el-button><el-button>批量导入</el-button><el-button type="success" @click="run">执行测试</el-button></template></PageToolbar><DataTable :data="rows"><el-table-column prop="question" label="示例问题"/><el-table-column prop="domain" label="业务域"/><el-table-column prop="expected" label="预期"/><el-table-column prop="result" label="结果"/><el-table-column label="操作"><template #default="s"><el-button link>查看结果</el-button></template></el-table-column></DataTable></el-card></template>
<script setup lang="ts">import { ref } from 'vue'; import PageToolbar from '@/components/PageToolbar.vue'; import DataTable from '@/components/DataTable.vue'; const q=ref(''); const rows=ref(['自然人申请光伏并网需要什么材料？','企业 10MW 屋顶光伏能不能余电上网？','居民阶梯电价怎么算？','高压新装需要哪些材料？'].map((question,i)=>({question,domain:['光伏并网','光伏并网','电价政策','业扩报装'][i],expected:'回答正确且引用依据',result:'待执行'}))); function add(){rows.value.unshift({question:'新建测试问题',domain:'通用',expected:'命中知识',result:'待执行'})} function run(){rows.value.forEach(r=>r.result='通过')}</script>
